#include "../../verification_stdlib.h"

int is_prime_simple(int n)
/*@ Require
      0 <= n && emp
    Ensure
      ((__return == 1 &&
        2 <= n@pre &&
        (forall (d: Z), (2 <= d && d < n@pre) => n@pre % d != 0)) ||
       (__return == 0 &&
        (n@pre < 2 ||
         (exists d, 2 <= d && d < n@pre && n@pre % d == 0)))) &&
      emp
*/
{
    int d;

    if (n < 2) {
        return 0;
    }

    for (d = 2; d < n; ++d) {
        if (n % d == 0) {
            return 0;
        }
    }

    return 1;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      0 < a + b &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}
Require Import ZArith.

Open Scope Z_scope.

Definition gcd_iterative_spec (a b r : Z) : Prop :=
  r = Z.gcd a b.

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

/*@ Extern Coq (array_count_even_spec : list Z -> Z) */
/*@ Import Coq Require Import array_count_even */

int array_count_even(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == array_count_even_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    for (i = 0; i < n; ++i) {
        if (a[i] % 2 == 0) {
            cnt++;
        }
    }

    return cnt;
}
Require Import ZArith.
Require Import Coq.Lists.List.

Open Scope Z_scope.

Fixpoint array_count_even_spec (l : list Z) : Z :=
  match l with
  | nil => 0
  | x :: xs =>
      (if Z.eq_dec (Z.rem x 2) 0 then 1 else 0) + array_count_even_spec xs
  end.

